// main.go
package main

import (
	"context"
	"fmt"
	"log"
	"net"

	"google.golang.org/grpc"
	"google.golang.org/grpc/reflection"
)

// TransactionServiceServer implementation
type transactionServiceServer struct {
	transaction.UnimplementedTransactionServiceServer
	accounts map[string]float64
}

func (s *transactionServiceServer) CreateTransaction(ctx context.Context, req *transaction.CreateTransactionRequest) (*transaction.CreateTransactionResponse, error) {
	// Validate request
	if req.TransactionId == "" || req.FromAccount == "" || req.ToAccount == "" || req.Amount <= 0 {
		return &transaction.CreateTransactionResponse{
			Success: false,
			Message: "Invalid transaction request",
		}, nil
	}

	// Check if from account has sufficient balance
	fromBalance, exists := s.accounts[req.FromAccount]
	if !exists {
		return &transaction.CreateTransactionResponse{
			Success: false,
			Message: "From account not found",
		}, nil
	}

	if fromBalance < req.Amount {
		return &transaction.CreateTransactionResponse{
			Success: false,
			Message: "Insufficient balance",
		}, nil
	}

	// Perform transaction
	s.accounts[req.FromAccount] -= req.Amount
	s.accounts[req.ToAccount] += req.Amount

	return &transaction.CreateTransactionResponse{
		Success: true,
		Message: "Transaction completed successfully",
		TransactionId: req.TransactionId,
	}, nil
}

func (s *transactionServiceServer) GetBalance(ctx context.Context, req *transaction.GetBalanceRequest) (*transaction.GetBalanceResponse, error) {
	// Validate request
	if req.AccountId == "" {
		return &transaction.GetBalanceResponse{
			Balance: 0,
			Currency: "USD",
			AccountId: req.AccountId,
		}, nil
	}

	balance, exists := s.accounts[req.AccountId]
	if !exists {
		return &transaction.GetBalanceResponse{
			Balance: 0,
			Currency: "USD",
			AccountId: req.AccountId,
		}, nil
	}

	return &transaction.GetBalanceResponse{
		Balance: balance,
		Currency: "USD",
		AccountId: req.AccountId,
	}, nil
}

func main() {
	// Initialize accounts map
	accounts := make(map[string]float64)
	accounts["acc1"] = 1000.0
	accounts["acc2"] = 500.0
	accounts["acc3"] = 2000.0

	// Create gRPC server
	server := grpc.NewServer()
	
	// Register service
	transaction.RegisterTransactionServiceServer(server, &transactionServiceServer{
		accounts: accounts,
	})
	
	// Enable reflection for tools like grpcurl
	reflection.Register(server)

	// Listen on port
	lis, err := net.Listen("tcp", ":50051")
	if err != nil {
		log.Fatalf("Failed to listen: %v", err)
	}

	fmt.Println("Transaction service listening on :50051")
	
	// Start server
	if err := server.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}